+        // Adding positive evidence should monotonically increase probability.
+        for _ in 0..5 {
+            ledger.record(EvidenceSource::Da2Response, 1.0);
+            let new_prob = ledger.probability();
+            assert!(
+                new_prob >= prev_prob,
+                "Probability should be monotone: {} < {}",
+                new_prob,
+                prev_prob
+            );
+            prev_prob = new_prob;
+        }
