+        sorted[idx.min(sorted.len() - 1)]
+    }
+
+    fn p99(sorted: &[u128]) -> u128 {
+        let idx = (sorted.len() as f64 * 0.99) as usize;
+        sorted[idx.min(sorted.len() - 1)]
+    }
